# ANTI-PATTERN: Redundant Context & Unchecked Parallelism
class CricketAnalysisAgentAntiPattern:
    def analyze_match(self, match_data):
        # ❌ Full context passed to every tool
        batting_stats = self.llm.call(
            f"Analyze batting: {match_data}",
            model="gpt-4",
            temperature=0.9  # Wasteful sampling
        )

        bowling_stats = self.llm.call(
            f"Analyze bowling: {match_data}",  # Duplicate context
            model="gpt-4"
        )

        field_analysis = self.llm.call(
            f"Analyze field: {match_data}",  # Repeated again
            model="gpt-4"
        )
        # Results: 3x context overhead, ~$0.45 per call

# BEST PRACTICE: Context Reuse & Cascading
class CricketAnalysisAgentOptimized:
    def analyze_match(self, match_data):
        # ✅ Classify query type once with lightweight model
        query_type = self.llm.call(
            f"Query type (batting|bowling|field): {match_data['summary']}",
            model="gpt-3.5-turbo",  # $0.0015 per 1K tokens
            temperature=0.1  # Deterministic
        )

        # ✅ Route only relevant context to expensive model
        if query_type == "batting":
            analysis = self.llm.call(
                f"Detailed batting analysis: {match_data['batting']}",
                model="gpt-4"  # Only when needed
            )
        elif query_type == "bowling":
            analysis = self.llm.call(
                f"Bowling metrics: {match_data['bowling']}",
                model="gpt-4"
            )

        # ✅ Parallel independent sub-tasks with shared base context
        base_context = {"format": match_data["format"], "venue": match_data["venue"]}
        results = self._parallel_execute([
            ("momentum", self._compute_momentum, base_context),
